-- ----------------------------
-- Table structure for zen_db_ds
-- ----------------------------
DROP TABLE IF EXISTS `zen_db_ds`;
CREATE TABLE `zen_db_ds`  (
  `PK_DS` decimal(38, 0) NOT NULL COMMENT '主键',
  `DB_TYPE` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据库类型',
  `CONN_TYPE` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '连接方式 1主机2URL',
  `NAME` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `HOST` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `PORT` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '端口号',
  `DB_SCHEMA` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据库',
  `URL` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '链接地址',
  `USER_NAME` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名',
  `USER_PWD` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '密码',
  `DRIVER` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '驱动',
  `CONN_MAX` decimal(10, 0) NULL DEFAULT NULL COMMENT '最大连接数',
  `CONN_MIN` decimal(10, 0) NULL DEFAULT NULL COMMENT '最小连接数',
  `DES` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '描述',
  `IS_SYS` decimal(1, 0) NULL DEFAULT 0 COMMENT '是否系统数据',
  `IS_LOCK` decimal(1, 0) NULL DEFAULT 0 COMMENT '是否锁定数据',
  `PK_CREATEDBY` decimal(38, 0) NULL DEFAULT NULL COMMENT '创建人',
  `DT_CREATED` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `PK_MODIFIEDBY` decimal(38, 0) NULL DEFAULT NULL COMMENT '修改人',
  `DT_MODIFIED` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `DS` decimal(1, 0) NULL DEFAULT 0 COMMENT '删除标志',
  `VERSION` decimal(10, 0) NULL DEFAULT NULL COMMENT '版本',
  PRIMARY KEY (`PK_DS`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '数据源' ROW_FORMAT = DYNAMIC;

