-- Table structure for zen_db_exec_log
-- ----------------------------
DROP TABLE IF EXISTS `zen_db_exec_log`;
CREATE TABLE `zen_db_exec_log`  (
  `PK_LOG` decimal(38, 0) NOT NULL COMMENT '主键',
  `PK_DS` decimal(38, 0) NULL DEFAULT NULL COMMENT '数据源ID',
  `DB_SCHEMA` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数据库名',
  `SQL_TEXT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '执行的SQL内容',
  `SQL_TYPE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'SQL类型 DDL/DML',
  `EXEC_STATUS` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '执行状态 SUCCESS/FAIL',
  `EXEC_TIME_MS` decimal(10, 0) NULL DEFAULT NULL COMMENT '执行耗时毫秒',
  `ERROR_MSG` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '错误信息',
  `AFFECTED_ROWS` decimal(38, 0) NULL DEFAULT NULL COMMENT '影响行数',
  `PK_CREATEDBY` decimal(38, 0) NULL DEFAULT NULL COMMENT '执行人',
  `DT_CREATED` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '执行时间',
  PRIMARY KEY (`PK_LOG`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'SQL执行审计日志' ROW_FORMAT = Dynamic;

