-- Table structure for zen_schedule
-- ----------------------------
DROP TABLE IF EXISTS `zen_schedule`;
CREATE TABLE `zen_schedule`  (
  `pk_schedule` decimal(38, 0) NOT NULL COMMENT '任务主键',
  `pk_schedule_group` decimal(38, 0) NULL DEFAULT NULL COMMENT '分组主键',
  `name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '定时任务名称',
  `job_class` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '任务类',
  `trigger_type` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '触发器类型 simple简单触发器固定间隔 cron日程触发器',
  `trigger_expr` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '表达式, CRON或秒',
  `clob_cfg` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '配置信息',
  `principal` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '负责人',
  `is_active` decimal(1, 0) NULL DEFAULT NULL COMMENT '是否激活1激活0未激活',
  `clob_run_time` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '运行时信息',
  `last_run_status` decimal(1, 0) NULL DEFAULT NULL COMMENT '上次运行状态1成功0失败',
  `des` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '描述',
  `pk_createdby` decimal(38, 0) NULL DEFAULT NULL COMMENT '创建人',
  `dt_created` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `pk_modifiedby` decimal(38, 0) NULL DEFAULT NULL COMMENT '修改人',
  `dt_modified` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `ds` decimal(1, 0) NULL DEFAULT 0 COMMENT '删除标志',
  `version` decimal(10, 0) NULL DEFAULT NULL COMMENT '版本',
  PRIMARY KEY (`pk_schedule`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of zen_schedule
-- ----------------------------

