CREATE TABLE `zen_schedule_group`  (
  `pk_schedule_group` decimal(38, 0) NOT NULL COMMENT '主键',
  `name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分组名称',
  `pk_createdby` decimal(38, 0) NULL DEFAULT NULL COMMENT '创建人',
  `dt_created` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `pk_modifiedby` decimal(38, 0) NULL DEFAULT NULL COMMENT '修改人',
  `dt_modified` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `ds` decimal(1, 0) NULL DEFAULT 0 COMMENT '删除标志',
  `version` decimal(10, 0) NULL DEFAULT NULL COMMENT '版本',
  PRIMARY KEY (`pk_schedule_group`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务分组' ROW_FORMAT = DYNAMIC;

