-- ----------------------------
-- Table structure for zen_schedule_log
-- ----------------------------
DROP TABLE IF EXISTS `zen_schedule_log`;
CREATE TABLE `zen_schedule_log`  (
  `pk_schedule_log` decimal(38, 0) NOT NULL COMMENT '主键',
  `pk_schedule` decimal(38, 0) NULL DEFAULT NULL COMMENT '任务主键',
  `dt_run` datetime NULL DEFAULT NULL COMMENT '运行时间',
  `status_run` decimal(1, 0) NULL DEFAULT NULL COMMENT '运行状态 1成功0失败 2执行中',
  `result_run` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '运行结果',
  `elapsed_time` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '耗时 ms',
  `clob_log` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '运行日志',
  `run_node` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '运行节点标志',
  `run_cfg` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '运行时配置',
  `is_manual` decimal(1, 0) NULL DEFAULT NULL COMMENT '是否手动',
  `pk_createdby` decimal(38, 0) NULL DEFAULT NULL COMMENT '创建人',
  `dt_created` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `pk_modifiedby` decimal(38, 0) NULL DEFAULT NULL COMMENT '修改人',
  `dt_modified` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `ds` decimal(1, 0) NULL DEFAULT 0 COMMENT '删除标志',
  `version` decimal(10, 0) NULL DEFAULT NULL COMMENT '版本',
  PRIMARY KEY (`pk_schedule_log`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '定时任务日志' ROW_FORMAT = DYNAMIC;

