DROP TABLE IF EXISTS `zen_sys_menu`;
CREATE TABLE `zen_sys_menu`  (
  `PK_MENU` decimal(38, 0) NOT NULL COMMENT '主键',
  `PK_PARENT` decimal(38, 0) NULL DEFAULT NULL COMMENT '父主键',
  `SUB_COUNT` decimal(10, 0) NULL DEFAULT 0 COMMENT '子菜单数目',
  `NODE_TYPE` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '菜单类型（功能节点、外链等）',
  `NAME` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '菜单名称',
  `ICON` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '菜单图标',
  `URL` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '菜单组件路径/外链地址',
  `COMPONENT` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '前端组件路径',
  `SORT_ORDER` decimal(10, 0) NULL DEFAULT NULL COMMENT '排序',
