-- ==========================================
-- 对象存储模块新增字段 DDL
-- 新增字段：is_default, tags
-- ==========================================

-- MySQL DDL
-- ==========================================
ALTER TABLE `zen_fso_ds`
    ADD COLUMN `IS_DEFAULT` TINYINT(1) DEFAULT 0 COMMENT '是否默认数据源',
    ADD COLUMN `TAGS` VARCHAR(500) DEFAULT NULL COMMENT '标签(格式: 生产:primary,测试:warning)';

-- 创建索引（可选，用于快速查询默认数据源）
CREATE INDEX `idx_is_default` ON `zen_fso_ds` (`IS_DEFAULT`);


ALTER TABLE `zen_redis_ds`
    ADD COLUMN `IS_DEFAULT` TINYINT(1) DEFAULT 0 COMMENT '是否默认数据源',
    ADD COLUMN `TAGS` VARCHAR(500) DEFAULT NULL COMMENT '标签(格式: 生产:primary,测试:warning)';

CREATE INDEX `idx_redis_is_default` ON `zen_redis_ds` (`IS_DEFAULT`);


-- MySQL DDL
ALTER TABLE `zen_db_exec_log`
    ADD COLUMN `DML_TYPE` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'DML子类型 INSERT/UPDATE/DELETE' AFTER `SQL_TYPE`,
    ADD COLUMN `SINGLE_TABLE_QUERY` decimal(1, 0) NULL DEFAULT NULL COMMENT '是否为单表查询 1是0否' AFTER `DML_TYPE`,
    ADD COLUMN `PK_COLUMN` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '主键列名（单表查询时有值）' AFTER `SINGLE_TABLE_QUERY`,
    ADD COLUMN `QUERY_TABLE` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '查询的表名（单表查询时有值）' AFTER `PK_COLUMN`,
    ADD COLUMN `QUERY_SCHEMA` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '查询的schema（SQL指定时优先，否则为数据源默认schema）' AFTER `QUERY_TABLE`;

-- SSH服务器表添加收藏时间和标签字段
