-- 添加收藏时间字段
ALTER TABLE `zen_ssh`
    ADD COLUMN `DT_FAVORITE` DATETIME NULL DEFAULT NULL COMMENT '收藏时间' AFTER `VERSION`;

-- 添加标签字段
ALTER TABLE `zen_ssh`
    ADD COLUMN `TAGS` VARCHAR(500) NULL DEFAULT NULL COMMENT '标签(逗号分隔，如: 生产:primary,测试:warning)' AFTER `DT_FAVORITE`;

-- 添加索引优化排序查询
ALTER TABLE `zen_ssh`
    ADD INDEX `idx_favorite_created` (`DT_FAVORITE` DESC, `DT_CREATED` DESC);
